module AdminHelper
  def admin_nav_link(label, path, icon: nil)
    active = current_page?(path) || (path != admin_root_path && request.path.start_with?(path))
    classes = if active
      "flex items-center gap-3 px-3 py-2 rounded-lg bg-white/10 text-white text-sm font-medium"
    else
      "flex items-center gap-3 px-3 py-2 rounded-lg text-white/60 hover:text-white hover:bg-white/5 text-sm transition-colors"
    end

    link_to path, class: classes do
      content_tag(:span, admin_icon(icon), class: "w-5 h-5") +
      content_tag(:span, label)
    end
  end

