  def stat_change_badge(value)
    if value > 0
      content_tag(:span, "+#{value}%", class: "text-xs text-success font-medium")
    elsif value < 0
      content_tag(:span, "#{value}%", class: "text-xs text-danger font-medium")
    else
      content_tag(:span, "0%", class: "text-xs text-secondary font-medium")
    end
  end
end
